// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PriMEDeal {
    struct Listing {
        address payable seller;
        bytes32 hD;                // hash of OKVS
        bytes32 comPB;             // commitment to buyer policy
        uint256 tb;                // threshold
        bytes32 hk2;               // hash of partial key k2
        bytes32 root;              // Merkle root of encrypted file
        bytes sigmaRoot;           // seller's signature on root
        uint256 v;                 // payment amount
        uint256 d;                 // collateral amount
        bytes S0;                  // token signature
        bytes pubData;             // other public data for ZKP
        ListingStatus status;
        uint256 timer;
        bytes32 k2;                // revealed partial key (if any)
    }

    enum ListingStatus { Inactive, Active, Challenged, Revealed, Disputed }

    mapping(bytes32 => Listing) public listings;
    uint256 public constant CHALLENGE_WINDOW = 1 days;
    uint256 public constant DISPUTE_WINDOW = 1 hours;

    event Listed(bytes32 indexed sid, address indexed seller, uint256 v, uint256 d);
    event Bought(bytes32 indexed sid, address indexed buyer);
    event KeyRevealed(bytes32 indexed sid, bytes32 k2);
    event Challenged(bytes32 indexed sid, address indexed buyer, uint256[] indices);
    event Settled(bytes32 indexed sid);

    modifier onlySeller(bytes32 sid) {
        require(msg.sender == listings[sid].seller, "Not seller");
        _;
    }

    function list(
        bytes32 sid,
        bytes32 hD,
        bytes32 comPB,
        uint256 tb,
        bytes32 hk2,
        bytes32 root,
        bytes calldata sigmaRoot,
        bytes calldata S0,
        bytes calldata pubData
    ) external payable {
        require(listings[sid].status == ListingStatus.Inactive, "Already listed");
        uint256 d = msg.value;
        // assume v = d / log2(tb) simplified
        listings[sid] = Listing({
            seller: payable(msg.sender),
            hD: hD,
            comPB: comPB,
            tb: tb,
            hk2: hk2,
            root: root,
            sigmaRoot: sigmaRoot,
            v: d,                     // simplified for gas test
            d: d,
            S0: S0,
            pubData: pubData,
            status: ListingStatus.Active,
            timer: 0,
            k2: bytes32(0)
        });
        emit Listed(sid, msg.sender, d, d);
    }

    function buy(
        bytes32 sid,
        bytes32 comAB,
        bytes calldata proof,
        bytes calldata pubInput
    ) external payable {
        Listing storage l = listings[sid];
        require(l.status == ListingStatus.Active, "Not active");
        require(msg.value == l.v, "Incorrect payment");

        // Groth16 verification using BN254 precompile (EIP-197)
        bool valid = verifyGroth16(pubInput, proof);
        require(valid, "Invalid proof");

        l.status = ListingStatus.Challenged;
        l.timer = block.timestamp + CHALLENGE_WINDOW;
        emit Bought(sid, msg.sender);
    }

    function reveal(bytes32 sid, bytes32 k2) external onlySeller(sid) {
        Listing storage l = listings[sid];
        require(l.status == ListingStatus.Challenged, "Not challenged");
        require(block.timestamp < l.timer, "Challenge expired");
        require(sha256(abi.encodePacked(k2)) == l.hk2, "Hash mismatch");

        l.k2 = k2;
        l.status = ListingStatus.Revealed;
        l.timer = block.timestamp + DISPUTE_WINDOW;
        emit KeyRevealed(sid, k2);
    }

    function challenge(
        bytes32 sid,
        uint256[] calldata indices,
        bytes[] calldata blocks,
        bytes[] calldata proofs
    ) external {
        Listing storage l = listings[sid];
        require(l.status == ListingStatus.Revealed, "Key not revealed");
        require(block.timestamp < l.timer, "Dispute window expired");

        // simplified audit: check Merkle proofs (omitted for gas estimation)
        // in real implementation, verify Merkle proof for each block
        // Here we just simulate storage read costs.

        // If any check fails, penalize seller
        // For gas test we just revert to simulate failure branch
        // To keep test simple, we always mark disputed here (assume honest buyer)
        l.status = ListingStatus.Disputed;
        emit Challenged(sid, msg.sender, indices);
    }

    function settle(bytes32 sid) external {
        Listing storage l = listings[sid];
        if (l.status == ListingStatus.Revealed && block.timestamp >= l.timer) {
            // release funds
            (bool ok, ) = l.seller.call{value: l.v}("");
            require(ok);
            l.status = ListingStatus.Inactive;
            emit Settled(sid);
        } else if (l.status == ListingStatus.Challenged && block.timestamp >= l.timer) {
            // timeout: refund buyer, penalize seller
            (bool ok, ) = msg.sender.call{value: l.v + l.d}("");
            require(ok);
            l.status = ListingStatus.Disputed;
        }
    }

    // Dummy Groth16 verifier (calls precompile 0x08)
    function verifyGroth16(bytes calldata input, bytes calldata proof) internal view returns (bool) {
        uint256[24] memory m;
        uint256 len = input.length;
        require(len % 32 == 0, "input length not multiple of 32");
        assembly {
            if iszero(staticcall(gas(), 0x08, add(input.offset, 32), mload(input.offset), mload(proof.offset), mload(proof.offset))) {
                revert(0,0)
            }
        }
        return m[0] != 0;
    }
}

